#!/usr/bin/env node
/**
 * Performance harness for the sessions parser — the hot path that scales
 * with session count. Bundles the real parser to a temp CJS module with
 * esbuild, points it at a synthetic ~/.claude generated by
 * generate-fixtures.mjs (via HOME / USERPROFILE), and measures:
 *
 *   - cold parse time           (parseSessions over N session files)
 *   - grouping time             (groupSessions on the parsed list)
 *   - stats aggregation time    (getStats)
 *   - search latency            (searchSessions for a common term)
 *   - rss delta                 (process memory before/after parse)
 *   - serialized payload size   (JSON.stringify of grouped list — the
 *                                postMessage payload the host would send)
 *
 * Emits a JSON report on stdout. A v1.10.0 baseline is embedded; any metric
 * that regresses >10% is surfaced as a warning (non-blocking, per F3 spec).
 *
 * Usage:
 *   node scripts/perf/measure.mjs [--count 5000] [--root <dir>] [--out report.json]
 */
import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";
import { execFileSync } from "node:child_process";
import { build } from "esbuild";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(__dirname, "../..");

function arg(name, fallback) {
  const i = process.argv.indexOf(`--${name}`);
  return i >= 0 && process.argv[i + 1] ? process.argv[i + 1] : fallback;
}

const count = Number.parseInt(arg("count", "5000"), 10);
const root = arg("root", path.join(os.tmpdir(), "claude-manager-perf-home"));
const outPath = arg("out", "");

// v1.10.0 baseline (single-run, dev laptop). Used only to flag >10%
// regressions; absolute numbers vary by machine so CI treats this as
// advisory, never a hard gate.
const BASELINE = {
  parseMs: 1400,
  groupMs: 60,
  statsMs: 40,
  searchMs: 30,
};

function ms(fn) {
  const t = process.hrtime.bigint();
  const result = fn();
  const elapsed = Number(process.hrtime.bigint() - t) / 1e6;
  return { elapsed, result };
}

async function main() {
  // 1. Generate fixtures.
  const genOut = execFileSync(
    process.execPath,
    [path.join(__dirname, "generate-fixtures.mjs"), "--count", String(count), "--root", root],
    { encoding: "utf8" },
  );
  const fixture = JSON.parse(genOut.trim().split("\n").pop());

  // 2. Bundle the parser to a temp CJS module so we can require it with a
  //    patched HOME. The parser captures PROJECTS_DIR from os.homedir() at
  //    import time, so HOME must be set before the require.
  const bundlePath = path.join(os.tmpdir(), "cm-perf-parser.cjs");
  await build({
    entryPoints: [path.join(repoRoot, "src/features/sessions/parser.ts")],
    bundle: true,
    platform: "node",
    format: "cjs",
    target: "node20",
    outfile: bundlePath,
    logLevel: "silent",
  });

  // 3. Patch env + import. require() picks up the just-set HOME.
  process.env.HOME = root;
  process.env.USERPROFILE = root;
  const { createRequire } = await import("node:module");
  const require = createRequire(pathToFileURL(path.join(repoRoot, "package.json")));
  const parser = require(bundlePath);

  const rssBefore = process.memoryUsage().rss;

  const parse = ms(() => parser.parseSessions({}));
  const sessions = parse.result;

  const group = ms(() => parser.groupSessions(sessions));
  const stats = ms(() => parser.getStats(sessions));
  const search = ms(() => parser.searchSessions(sessions, "reply"));

  const rssAfter = process.memoryUsage().rss;
  const payloadBytes = Buffer.byteLength(JSON.stringify(group.result), "utf8");

  const metrics = {
    parseMs: round(parse.elapsed),
    groupMs: round(group.elapsed),
    statsMs: round(stats.elapsed),
    searchMs: round(search.elapsed),
    rssDeltaMb: round((rssAfter - rssBefore) / 1024 / 1024),
    payloadKb: round(payloadBytes / 1024),
    sessionsParsed: Array.isArray(sessions) ? sessions.length : 0,
  };

  const warnings = [];
  for (const key of Object.keys(BASELINE)) {
    const base = BASELINE[key];
    const cur = metrics[key];
    if (typeof cur === "number" && cur > base * 1.1) {
      warnings.push(`${key}: ${cur}ms vs baseline ${base}ms (>10% regression)`);
    }
  }

  const report = {
    generatedAt: new Date().toISOString(),
    fixture,
    node: process.version,
    platform: process.platform,
    metrics,
    baseline: BASELINE,
    warnings,
  };

  const json = JSON.stringify(report, null, 2);
  if (outPath) fs.writeFileSync(outPath, json);
  console.log(json);

  if (warnings.length > 0) {
    console.warn(`\n[perf] ${warnings.length} metric(s) regressed >10% — review (non-blocking).`);
  }
}

function round(n) {
  return Math.round(n * 100) / 100;
}

main().catch((err) => {
  console.error("perf measure failed:", err);
  process.exit(1);
});
